sql:
SELECT COUNT(session_id) AS session_count
FROM capture_sessions
WHERE created_by = 1;

external_knowledge:
; Top 3 capture sessions refer to the sessions with the highest number of frames; 
; The top 3 sessions are determined by ranking the sessions based on the number of frames in descending order;
; Associated teams and users are those that are linked to the top 3 sessions through the session_teams and team_users tables.

